package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";

    // Use reflection to create instance since constructor is not visible or incomplete
    Class<?> clazz = Class.forName("com.google.gson.examples.android.model.LineItem");
    java.lang.reflect.Constructor<?> constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance("ItemName", 5, 123456L, expectedCurrencyCode);

    // Use reflection to invoke getCurrencyCode method
    java.lang.reflect.Method method = clazz.getDeclaredMethod("getCurrencyCode");
    method.setAccessible(true);
    String actualCurrencyCode = (String) method.invoke(lineItem);

    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
